const body = $json.body;
const textBody = typeof body === 'string'
  ? body
  : JSON.stringify(body ?? {}, null, 2);

const normalizedText = textBody
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 12000);

return [{
  json: {
    service: $json.service,
    source: $json.source,
    source_url: $json.url,
    status_code: $json.statusCode,
    fetched_at: new Date().toISOString(),
    services: $json.services,
    current_date: $json.current_date,
    prev_report: $json.prev_report,
    mode: $json.mode,
    raw_item: {
      title: `${$json.service} / ${$json.source}`,
      raw_text: normalizedText,
    },
  },
}];

const items = $input.all().map((entry) => entry.json);
const first = items[0] ?? {};

return [{
  json: {
    current_date: first.current_date || new Date().toISOString(),
    prev_report: first.prev_report || '',
    mode: first.mode || 'MODE_A',
    services_json: JSON.stringify(first.services || []),
    raw_items_json: JSON.stringify(items.map((item) => ({
      service: item.service,
      source: item.source,
      source_url: item.source_url,
      fetched_at: item.fetched_at,
      status_code: item.status_code,
      raw_item: item.raw_item,
    }))),
  },
}];

