const responseBody = $json.body ?? {};
let content = responseBody.output_text;

if (!content && Array.isArray(responseBody.output)) {
  const textChunks = [];
  for (const item of responseBody.output) {
    if (!Array.isArray(item.content)) continue;
    for (const part of item.content) {
      if (part.type === 'output_text' && part.text) textChunks.push(part.text);
    }
  }
  content = textChunks.join('\n');
}

let report;
try {
  report = typeof content === 'string' ? JSON.parse(content) : content;
} catch (error) {
  report = {
    summary: {
      date: new Date().toISOString().slice(0, 10),
      top_deals_count: 0,
      new_count: 0,
      changed_count: 0,
      expired_count: 0,
    },
    top_deals: [],
    expired: [],
    notes: ['OpenAI response was not valid JSON', String(error.message || error)],
  };
}

const topDeals = Array.isArray(report.top_deals) ? report.top_deals : [];
const lines = [
  'AI TOOLS DEAL MONITOR',
  `Date: ${report.summary?.date || new Date().toISOString().slice(0, 10)}`,
  '',
  'Top deals today:',
];

if (topDeals.length === 0) {
  lines.push('No high-confidence deals found.');
} else {
  for (const deal of topDeals.slice(0, 5)) {
    lines.push(`${deal.rank}. ${deal.service} — ${deal.title} (${deal.discount_text})`);
  }
}

lines.push('');
lines.push(`New deals: ${report.summary?.new_count ?? 0}`);
lines.push(`Changed: ${report.summary?.changed_count ?? 0}`);
lines.push(`Expired: ${report.summary?.expired_count ?? 0}`);

return [{
  json: {
    report,
    telegram_text: lines.join('\n'),
  },
}];
